```c
#include <stdio.h>
#include <stdint.h>
#include <blosc.h>

#define SRC_SIZE 1024
#define DST_SIZE 4294967296ULL

int main(){
  
  /* Allocate Input and output data byte buffers*/
  uint8_t *src = malloc(SRC_SIZE);
  uint8_t *dst = malloc(DST_SIZE);
  /* Check if the allocation was successful*/
  if(src == NULL || dst == NULL){
    printf("Memory allocation failed\n");
    return 1;
  }

  /* Fill the input data buffer  with random bytes*/
  srand(1234);
  for(int i=0;i<SRC_SIZE;i++){
    src[i] = (uint8_t)rand();
  }

  int csize = blosc_compress_ctx(5, 1, 1,
                            SRC_SIZE, src, dst, DST_SIZE,
                            "lz4", 0, 1);
  printf("Compression Returned: %d\n", csize);
  return 0;
}
```

Running this on a 64-bit system I get:

```
Compression Returned: 0
```
But compression should succeed.

The overflow is happening at:
https://github.com/Blosc/c-blosc/blob/dcf6813d46f9fcbf7af4395b5536f886dfc76dd0/blosc/blosc.c#L1080

There are some checks on `destsize` being too small, but from what I can tell, there are no checks on it being too large.
https://github.com/Blosc/c-blosc/blob/dcf6813d46f9fcbf7af4395b5536f886dfc76dd0/blosc/blosc.c#L1096-L1102

One option to fix this would be to clamp `destsize` to be at most `sourcesize + BLOSC_MAX_OVERHEAD`, this would also fix #159 ","reactions":{"url":"https://api.github.com/repos/Blosc/c-blosc/issues/389/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"timeline_url":"https://api.github.com/repos/Blosc/c-blosc/issues/389/timeline","performed_via_github_app":null,"state_reason":null}}

